+    /// Convert from POSIX integer constant.
+    pub fn from_posix(mode: i32) -> Option<BufMode> {
+        match mode {
+            IOFBF => Some(BufMode::Full),
+            IOLBF => Some(BufMode::Line),
+            IONBF => Some(BufMode::None),
+            _ => Option::None,
+        }
+    }
