+impl StreamBuffer {
+    /// Create a new buffer with the given mode and capacity.
+    pub fn new(mode: BufMode, capacity: usize) -> Self {
+        let cap = if matches!(mode, BufMode::None) {
+            0
+        } else {
+            capacity.max(1)
+        };
+        Self {
+            data: vec![0u8; cap],
+            pos: 0,
+            filled: 0,
+            mode,
+            io_started: false,
+        }
+    }
+
+    /// Create a fully-buffered buffer with default BUFSIZ.
